32	/*
33	 * Count the number of dimensions selected in 'axis_flags'
34	 */
35	static int
36	count_axes(int ndim, const npy_bool *axis_flags)
37	{
38	    int idim;
39	    int naxes = 0;
40	
41	    for (idim = 0; idim < ndim; ++idim) {
42	        if (axis_flags[idim]) {
43	            naxes++;
44	        }
45	    }
46	    return naxes;
47	}
