49	/*
50	 * This function initializes a result array for a reduction operation
51	 * which has no identity. This means it needs to copy the first element
52	 * it sees along the reduction axes to result.
53	 *
54	 * If a reduction has an identity, such as 0 or 1, the result should be
55	 * fully initialized to the identity, because this function raises an
56	 * exception when there are no elements to reduce (which is appropriate if,
57	 * and only if, the reduction operation has no identity).
58	 *
59	 * This means it copies the subarray indexed at zero along each reduction axis
60	 * into 'result'.
61	 *
62	 * result  : The array into which the result is computed. This must have
63	 *           the same number of dimensions as 'operand', but for each
64	 *           axis i where 'axis_flags[i]' is True, it has a single element.
65	 * operand : The array being reduced.
66	 * axis_flags : An array of boolean flags, one for each axis of 'operand'.
67	 *              When a flag is True, it indicates to reduce along that axis.
68	 * funcname : The name of the reduction operation, for the purpose of
69	 *            better quality error messages. For example, "numpy.max"
70	 *            would be a good name for NumPy's max function.
71	 *
72	 * Returns -1 if an error occurred, and otherwise the reduce arrays size,
73	 * which is the number of elements already initialized.
74	 */
75	static npy_intp
76	PyArray_CopyInitialReduceValues(
77	                    PyArrayObject *result, PyArrayObject *operand,
78	                    const npy_bool *axis_flags, const char *funcname,
79	                    int keepdims)
80	{
81	    npy_intp shape[NPY_MAXDIMS], strides[NPY_MAXDIMS];
82	    npy_intp *shape_orig = PyArray_SHAPE(operand);
83	    npy_intp *strides_orig = PyArray_STRIDES(operand);
84	    PyArrayObject *op_view = NULL;
85	
86	    int ndim = PyArray_NDIM(operand);
87	
88	    /*
89	     * Copy the subarray of the first element along each reduction axis.
90	     *
91	     * Adjust the shape to only look at the first element along
92	     * any of the reduction axes. If keepdims is False remove the axes
93	     * entirely.
94	     */
95	    int idim_out = 0;
96	    npy_intp size = 1;
97	    for (int idim = 0; idim < ndim; idim++) {
98	        if (axis_flags[idim]) {
99	            if (NPY_UNLIKELY(shape_orig[idim] == 0)) {
100	                PyErr_Format(PyExc_ValueError,
101	                        "zero-size array to reduction operation %s "
102	                        "which has no identity", funcname);
103	                return -1;
104	            }
105	            if (keepdims) {
106	                shape[idim_out] = 1;
107	                strides[idim_out] = 0;
108	                idim_out++;
109	            }
110	        }
111	        else {
112	            size *= shape_orig[idim];
113	            shape[idim_out] = shape_orig[idim];
114	            strides[idim_out] = strides_orig[idim];
115	            idim_out++;
116	        }
117	    }
118	
119	    PyArray_Descr *descr = PyArray_DESCR(operand);
120	    Py_INCREF(descr);
121	    op_view = (PyArrayObject *)PyArray_NewFromDescr(
122	            &PyArray_Type, descr, idim_out, shape, strides,
123	            PyArray_DATA(operand), 0, NULL);
124	    if (op_view == NULL) {
125	        return -1;
126	    }
127	
128	    /*
129	     * Copy the elements into the result to start.
130	     */
131	    int res = PyArray_CopyInto(result, op_view);
132	    Py_DECREF(op_view);
133	    if (res < 0) {
134	        return -1;
135	    }
136	
137	    /*
138	     * If there were no reduction axes, we would already be done here.
139	     * Note that if there is only a single reduction axis, in principle the
140	     * iteration could be set up more efficiently here by removing that
141	     * axis before setting up the iterator (simplifying the iteration since
142	     * `skip_first_count` (the returned size) can be set to 0).
143	     */
144	    return size;
145	}
146	
147	/*
148	 * This function executes all the standard NumPy reduction function
149	 * boilerplate code, just calling the appropriate inner loop function where
150	 * necessary.
151	 *
152	 * context     : The ArrayMethod context (with ufunc, method, and descriptors).
153	 * operand     : The array to be reduced.
154	 * out         : NULL, or the array into which to place the result.
155	 * wheremask   : Reduction mask of valid values used for `where=`.
156	 * axis_flags  : Flags indicating the reduction axes of 'operand'.
157	 * keepdims    : If true, leaves the reduction dimensions in the result
158	 *               with size one.
159	 * subok       : If true, the result uses the subclass of operand, otherwise
160	 *               it is always a base class ndarray.
161	 * initial     : Initial value, if NULL the default is fetched from the
162	 *               ArrayMethod (typically as the default from the ufunc).
163	 * loop        : `reduce_loop` from `ufunc_object.c`.  TODO: Refactor
164	 * buffersize  : Buffer size for the iterator. For the default, pass in 0.
165	 * funcname    : The name of the reduction function, for error messages.
166	 * errormask   : forwarded from _get_bufsize_errmask
167	 *
168	 * TODO FIXME: if you squint, this is essentially a second independent
169	 * implementation of generalized ufuncs with signature (i)->(), plus a few
170	 * extra bells and whistles. (Indeed, as far as I can tell, it was originally
171	 * split out to support a fancy version of count_nonzero... which is not
172	 * actually a reduction function at all, it's just a (i)->() function!) So
173	 * probably these two implementation should be merged into one. (In fact it
174	 * would be quite nice to support axis= and keepdims etc. for arbitrary
175	 * generalized ufuncs!)
176	 */
177	NPY_NO_EXPORT PyArrayObject *
178	PyUFunc_ReduceWrapper(PyArrayMethod_Context *context,
179	        PyArrayObject *operand, PyArrayObject *out, PyArrayObject *wheremask,
180	        npy_bool *axis_flags, int keepdims,
181	        PyObject *initial, PyArray_ReduceLoopFunc *loop,
182	        npy_intp buffersize, const char *funcname, int errormask)
183	{
184	    assert(loop != NULL);
185	    PyArrayObject *result = NULL;
186	    npy_intp skip_first_count = 0;
187	
188	    /* Iterator parameters */
189	    NpyIter *iter = NULL;
190	    PyArrayObject *op[3];
191	    PyArray_Descr *op_dtypes[3];
192	    npy_uint32 it_flags, op_flags[3];
193	    /* Loop auxdata (must be freed on error) */
194	    NpyAuxData *auxdata = NULL;
195	
196	    /* Set up the iterator */
197	    op[0] = out;
198	    op[1] = operand;
199	    op_dtypes[0] = context->descriptors[0];
200	    op_dtypes[1] = context->descriptors[1];
201	
202	    /* Buffer to use when we need an initial value */
203	    char *initial_buf = NULL;
204	
205	    /* More than one axis means multiple orders are possible */
206	    if (!(context->method->flags & NPY_METH_IS_REORDERABLE)
207	            && count_axes(PyArray_NDIM(operand), axis_flags) > 1) {
208	        PyErr_Format(PyExc_ValueError,
209	                "reduction operation '%s' is not reorderable, "
210	                "so at most one axis may be specified",
211	                funcname);
212	        goto fail;
213	    }
214	
215	    it_flags = NPY_ITER_BUFFERED |
216	            NPY_ITER_EXTERNAL_LOOP |
217	            NPY_ITER_GROWINNER |
218	            NPY_ITER_ZEROSIZE_OK |
219	            NPY_ITER_REFS_OK |
220	            NPY_ITER_DELAY_BUFALLOC |
221	            /*
222	             * stride negation (if reorderable) could currently misalign the
223	             * first-visit and initial value copy logic.
224	             */
225	            NPY_ITER_DONT_NEGATE_STRIDES |
226	            NPY_ITER_COPY_IF_OVERLAP;
227	
228	    op_flags[0] = NPY_ITER_READWRITE |
229	                  NPY_ITER_ALIGNED |
230	                  NPY_ITER_ALLOCATE |
231	                  NPY_ITER_NO_SUBTYPE;
232	    op_flags[1] = NPY_ITER_READONLY |
233	                  NPY_ITER_ALIGNED |
234	                  NPY_ITER_NO_BROADCAST;
235	
236	    if (wheremask != NULL) {
237	        op[2] = wheremask;
238	        /* wheremask is guaranteed to be NPY_BOOL, so borrow its reference */
239	        op_dtypes[2] = PyArray_DESCR(wheremask);
240	        assert(op_dtypes[2]->type_num == NPY_BOOL);
241	        if (op_dtypes[2] == NULL) {
242	            goto fail;
243	        }
244	        op_flags[2] = NPY_ITER_READONLY;
245	    }
246	    /* Set up result array axes mapping, operand and wheremask use default */
247	    int result_axes[NPY_MAXDIMS];
248	    int *op_axes[3] = {result_axes, NULL, NULL};
249	
250	    int curr_axis = 0;
251	    for (int i = 0; i < PyArray_NDIM(operand); i++) {
252	        if (axis_flags[i]) {
253	            if (keepdims) {
254	                result_axes[i] = NPY_ITER_REDUCTION_AXIS(curr_axis);
255	                curr_axis++;
256	            }
257	            else {
258	                result_axes[i] = NPY_ITER_REDUCTION_AXIS(-1);
259	            }
260	        }
261	        else {
262	            result_axes[i] = curr_axis;
263	            curr_axis++;
264	        }
265	    }
266	    if (out != NULL) {
267	        /* NpyIter does not raise a good error message in this common case. */
268	        if (NPY_UNLIKELY(curr_axis != PyArray_NDIM(out))) {
269	            if (keepdims) {
270	                PyErr_Format(PyExc_ValueError,
271	                        "output parameter for reduction operation %s has the "
272	                        "wrong number of dimensions: Found %d but expected %d "
273	                        "(must match the operand's when keepdims=True)",
274	                        funcname, PyArray_NDIM(out), curr_axis);
275	            }
276	            else {
277	                PyErr_Format(PyExc_ValueError,
278	                        "output parameter for reduction operation %s has the "
279	                        "wrong number of dimensions: Found %d but expected %d",
280	                        funcname, PyArray_NDIM(out), curr_axis);
281	            }
282	            goto fail;
283	        }
284	    }
285	
286	    iter = NpyIter_AdvancedNew(wheremask == NULL ? 2 : 3, op, it_flags,
287	                               NPY_KEEPORDER, NPY_UNSAFE_CASTING,
288	                               op_flags,
289	                               op_dtypes,
290	                               PyArray_NDIM(operand), op_axes, NULL, buffersize);
291	    if (iter == NULL) {
292	        goto fail;
293	    }
294	
295	    npy_bool empty_iteration = NpyIter_GetIterSize(iter) == 0;
296	    result = NpyIter_GetOperandArray(iter)[0];
297	
298	    /*
299	     * Get the initial value (if it exists).  If the iteration is empty
300	     * then we assume the reduction is also empty.  The reason is that when
301	     * the outer iteration is empty we just won't use the initial value
302	     * in any case.  (`np.sum(np.zeros((0, 3)), axis=0)` is a length 3
303	     * reduction but has an empty result.)
304	     */
305	    if ((initial == NULL && context->method->get_reduction_initial == NULL)
306	            || initial == Py_None) {
307	        /* There is no initial value, or initial value was explicitly unset */
308	    }
309	    else {
310	        /* Not all functions will need initialization, but init always: */
311	        initial_buf = PyMem_Calloc(1, op_dtypes[0]->elsize);
312	        if (initial_buf == NULL) {
313	            PyErr_NoMemory();
314	            goto fail;
315	        }
316	        if (initial != NULL) {
317	            /* must use user provided initial value */
318	            if (PyArray_Pack(op_dtypes[0], initial_buf, initial) < 0) {
319	                goto fail;
320	            }
321	        }
322	        else {
323	            /*
324	             * Fetch initial from ArrayMethod, we pretend the reduction is
325	             * empty when the iteration is.  This may be wrong, but when it is,
326	             * we will not need the identity as the result is also empty.
327	             */
328	            int has_initial = context->method->get_reduction_initial(
329	                    context, empty_iteration, initial_buf);
330	            if (has_initial < 0) {
331	                goto fail;
332	            }
333	            if (!has_initial) {
334	                /* We have no initial value available, free buffer to indicate */
335	                PyMem_FREE(initial_buf);
336	                initial_buf = NULL;
337	            }
338	        }
339	    }
340	
341	    PyArrayMethod_StridedLoop *strided_loop;
342	    NPY_ARRAYMETHOD_FLAGS flags;
343	
344	    npy_intp *strideptr = NpyIter_GetInnerStrideArray(iter);
345	    if (wheremask != NULL) {
346	        if (PyArrayMethod_GetMaskedStridedLoop(context,
347	                1, strideptr, &strided_loop, &auxdata, &flags) < 0) {
348	            goto fail;
349	        }
350	    }
351	    else {
352	        if (context->method->get_strided_loop(context,
353	                1, 0, strideptr, &strided_loop, &auxdata, &flags) < 0) {
354	            goto fail;
355	        }
356	    }
